namespace SecureLoggingExample
{
    /// <summary>
    /// Utility class for redacting and masking sensitive data before logging.
    /// </summary>
    public static class LogSanitizer
    {
        private static readonly HashSet<string> SensitiveHeaders = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            "Authorization", "Cookie", "Set-Cookie", "X-API-Key", "X-Auth-Token",
            "Proxy-Authorization", "WWW-Authenticate"
        };

        private static readonly HashSet<string> SensitiveFields = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            "password", "creditCard", "credit_card", "cardNumber", "card_number",
            "cvv", "cvc", "ssn", "social_security", "socialSecurity",
            "secret", "token", "apiKey", "api_key", "authorization"
        };

        public static Dictionary<string, string> SanitizeHeaders(IHeaderDictionary headers)
        {
            var sanitized = new Dictionary<string, string>();
            foreach (var header in headers)
            {
                sanitized[header.Key] = SensitiveHeaders.Contains(header.Key)
                    ? "[REDACTED]"
                    : header.Value.ToString();
            }
            return sanitized;
        }

        public static string MaskEmail(string email)
        {
            if (string.IsNullOrEmpty(email)) return "[empty]";
            var parts = email.Split('@');
            if (parts.Length != 2) return "[invalid-email]";
            var localPart = parts[0];
            var masked = localPart.Length <= 2
                ? "**"
                : localPart[0] + new string('*', localPart.Length - 2) + localPart[localPart.Length - 1];
            return $"{masked}@{parts[1]}";
        }

        public static string MaskCreditCard(string cardNumber)
        {
            if (string.IsNullOrEmpty(cardNumber)) return "[empty]";
            var digits = new string(cardNumber.Where(char.IsDigit).ToArray());
            if (digits.Length < 4) return "[REDACTED]";
            return $"****-****-****-{digits.Substring(digits.Length - 4)}";
        }

        public static string MaskUserId(string userId)
        {
            if (string.IsNullOrEmpty(userId)) return "[empty]";
            if (userId.Length <= 4) return "****";
            return userId.Substring(0, 4) + "****";
        }

        public static string RedactSensitiveFields(string json)
        {
            if (string.IsNullOrEmpty(json)) return "[empty]";
            try
            {
                var obj = JsonConvert.DeserializeObject<Dictionary<string, object>>(json);
                if (obj == null) return "[null]";

                var redacted = new Dictionary<string, object>();
                foreach (var kvp in obj)
                {
                    redacted[kvp.Key] = SensitiveFields.Contains(kvp.Key)
                        ? "[REDACTED]"
                        : kvp.Value;
                }
                return JsonConvert.SerializeObject(redacted);
            }
            catch
            {
                // If we can't parse it, don't log it raw - it might contain sensitive data
                return "[REDACTED - unparseable body]";
            }
        }
    }

    /// <summary>
    /// Secure Azure Function that demonstrates proper logging practices.
    /// - No PII in logs
    /// - No credentials/tokens in logs
    /// - No credit card numbers or SSNs
    /// - Correlation IDs for traceability
    /// - Structured logging with safe fields only
    /// </summary>
    public static class SecureOrderFunction
    {
        [FunctionName("SecureProcessOrder")]
        public static async Task<IActionResult> Run(
            [HttpTrigger(AuthorizationLevel.Function, "post", Route = "orders")] HttpRequest req,
            ILogger log)
        {
            // Generate a correlation ID for tracking this request across logs
            var correlationId = req.Headers["X-Correlation-ID"].FirstOrDefault() ?? Guid.NewGuid().ToString();

            // ✅ SAFE: Log only non-sensitive headers, redact sensitive ones
            var sanitizedHeaders = LogSanitizer.SanitizeHeaders(req.Headers);
            log.LogInformation("Request received. CorrelationId={CorrelationId}, Method={Method}, Path={Path}, " +
                "ContentType={ContentType}, ContentLength={ContentLength}",
                correlationId, req.Method, req.Path, req.ContentType, req.ContentLength);

            log.LogDebug("Sanitized headers for CorrelationId={CorrelationId}: {Headers}",
                correlationId, JsonConvert.SerializeObject(sanitizedHeaders));

            // ✅ SAFE: Read body but only log redacted version
            string requestBody;
            using (var reader = new StreamReader(req.Body))
            {
                requestBody = await reader.ReadToEndAsync();
            }

            // ✅ SAFE: Log redacted body (sensitive fields replaced with [REDACTED])
            string redactedBody = LogSanitizer.RedactSensitiveFields(requestBody);
            log.LogDebug("Redacted request body for CorrelationId={CorrelationId}: {RedactedBody}",
                correlationId, redactedBody);

            OrderRequest orderRequest;
            try
            {
                orderRequest = JsonConvert.DeserializeObject<OrderRequest>(requestBody);
            }
            catch (JsonException ex)
            {
                log.LogWarning("Invalid JSON in request body. CorrelationId={CorrelationId}, Error={Error}",
                    correlationId, ex.Message);
                return new BadRequestObjectResult(new { error = "Invalid request format", correlationId });
            }

            if (orderRequest == null)
            {
                log.LogWarning("Null order request. CorrelationId={CorrelationId}", correlationId);
                return new BadRequestObjectResult(new { error = "Empty request", correlationId });
            }

            // ✅ SAFE: Log masked/anonymized user identifiers
            log.LogInformation("Processing order. CorrelationId={CorrelationId}, MaskedUserId={MaskedUserId}, " +
                "MaskedEmail={MaskedEmail}, Amount={Amount}, HasCreditCard={HasCreditCard}",
                correlationId,
                LogSanitizer.MaskUserId(orderRequest.UserId),
                LogSanitizer.MaskEmail(orderRequest.Email),
                orderRequest.Amount,
                !string.IsNullOrEmpty(orderRequest.CreditCard));

            // ✅ SAFE: Validate auth without logging the token
            string authHeader = req.Headers["Authorization"].FirstOrDefault();
            bool hasAuth = !string.IsNullOrEmpty(authHeader);
            log.LogInformation("Authentication present: {HasAuth}, CorrelationId={CorrelationId}",
                hasAuth, correlationId);

            if (!hasAuth)
            {
                log.LogWarning("Missing authorization header. CorrelationId={CorrelationId}", correlationId);
                return new UnauthorizedResult();
            }

            string connectionString = Environment.GetEnvironmentVariable("SqlConnectionString");

            // ✅ SAFE: Never log connection strings
            log.LogDebug("Database connection configured: {IsConfigured}, CorrelationId={CorrelationId}",
                !string.IsNullOrEmpty(connectionString), correlationId);

            try
            {
                using (var connection = new SqlConnection(connectionString))
                {
                    await connection.OpenAsync();

                    // ✅ SAFE: Log query structure but NOT parameter values
                    string query = "INSERT INTO Orders (UserId, Email, CreditCard, Amount) VALUES (@UserId, @Email, @CreditCard, @Amount)";
                    log.LogDebug("Executing SQL insert into Orders table. CorrelationId={CorrelationId}, " +
                        "ParameterCount={ParameterCount}",
                        correlationId, 4);

                    var orderId = Guid.NewGuid();

                    using (var command = new SqlCommand(query, connection))
                    {
                        command.Parameters.AddWithValue("@UserId", orderRequest.UserId ?? "");
                        command.Parameters.AddWithValue("@Email", orderRequest.Email ?? "");
                        command.Parameters.AddWithValue("@CreditCard", orderRequest.CreditCard ?? "");
                        command.Parameters.AddWithValue("@Amount", orderRequest.Amount ?? 0m);

                        var rowsAffected = await command.ExecuteNonQueryAsync();

                        // ✅ SAFE: Log operation result without sensitive data
                        log.LogInformation("Order created successfully. CorrelationId={CorrelationId}, " +
                            "OrderId={OrderId}, RowsAffected={RowsAffected}, MaskedCard={MaskedCard}",
                            correlationId, orderId, rowsAffected,
                            LogSanitizer.MaskCreditCard(orderRequest.CreditCard));
                    }

                    return new OkObjectResult(new { message = "Order processed", orderId, correlationId });
                }
            }
            catch (SqlException ex)
            {
                // ✅ SAFE: Log exception details without sensitive context data
                log.LogError(ex, "Database error processing order. CorrelationId={CorrelationId}, " +
                    "SqlErrorNumber={ErrorNumber}, SqlState={State}, MaskedUserId={MaskedUserId}",
                    correlationId, ex.Number, ex.State,
                    LogSanitizer.MaskUserId(orderRequest.UserId));

                // ✅ SAFE: Return generic error without internal details
                return new ObjectResult(new
                {
                    error = "An error occurred processing your order. Please try again.",
                    correlationId
                })
                { StatusCode = 500 };
            }
            catch (Exception ex)
            {
                // ✅ SAFE: Log exception with correlation ID but no sensitive data
                log.LogError(ex, "Unexpected error processing order. CorrelationId={CorrelationId}, " +
                    "ExceptionType={ExceptionType}",
                    correlationId, ex.GetType().FullName);

                // ✅ SAFE: Generic error response - no stack traces or internal details exposed
                return new ObjectResult(new
                {
                    error = "An unexpected error occurred. Please contact support with your correlation ID.",
                    correlationId
                })
                { StatusCode = 500 };
            }
        }
    }

